1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	type Item = { type: string; cursed?: boolean; enchantment?: number };
16	type Step = { op: string; items: Item[] };
17	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
18	
19	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
20	
21	const BLOCK_SIZE = 3;
22	const COMPONENT_BLOCK_PRICE = 60;
23	
24	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
25	
26	const sumItemBasePremiums = (items: Item[]): number =>
27	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
28	
29	const groupByType = (items: Item[]): Map<string, Item[]> => {
30	  const groups = new Map<string, Item[]>();
31	  for (const item of items) {
32	    const group = groups.get(item.type) ?? [];
33	    group.push(item);
34	    groups.set(item.type, group);
35	  }
36	  return groups;
37	};
38	
39	const priceComponentGroup = (group: Item[]): number =>
40	  group.length === BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : sumItemBasePremiums(group);
41	
42	const computeBasePremium = (items: Item[]): number => {
43	  const components = items.filter(isComponent);
44	  const nonComponents = items.filter((item) => !isComponent(item));
45	  const componentGroups = [...groupByType(components).values()];
46	  const componentTotal = componentGroups.reduce(
47	    (sum, group) => sum + priceComponentGroup(group),
48	    0,
49	  );
50	  return sumItemBasePremiums(nonComponents) + componentTotal;
51	};
52	
53	const CURSE_SURCHARGE_RATE = 0.5;
54	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
55	const HIGH_ENCHANTMENT_THRESHOLD = 5;
56	
57	const itemSurcharge = (item: Item): number => {
58	  const base = itemBasePremium(item);
59	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
60	  const enchantment =
61	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
62	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
63	      : 0;
64	  return curse + enchantment;
65	};
66	
67	const sumItemSurcharges = (items: Item[]): number =>
68	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
69	
70	const LOYALTY_DISCOUNT_RATE = 0.2;
71	const LOYALTY_THRESHOLD_YEARS = 2;
72	
73	const quoteStep = (step: Step, customer: { yearsWithMHPCO: number }): { premium: number } => {
74	  const base = computeBasePremium(step.items);
75	  const surcharges = sumItemSurcharges(step.items);
76	  const firstInsurance = base * FIRST_INSURANCE_RATE;
77	  const loyaltyDiscount =
78	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
79	  return {
80	    premium: Math.ceil(base + surcharges + firstInsurance - loyaltyDiscount + PROCESSING_FEE),
81	  };
82	};
83	
84	export const runScenario = (scenario: unknown): unknown => {
85	  const { customer, steps } = scenario as Scenario;
86	  return { results: steps.map((step) => quoteStep(step, customer)) };
87	};
