const loyaltyDiscount = (base: number, customer: { yearsWithMHPCO: number }): number =>
  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;

const quoteStep = (step: Step, customer: { yearsWithMHPCO: number }): { premium: number } => {
  const base = computeBasePremium(step.items);
  const itemSurcharges = sumItemSurcharges(step.items);
  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
  const discounts = loyaltyDiscount(base, customer);
  return {
    premium: Math.ceil(
      base + itemSurcharges + firstInsuranceSurcharge - discounts + PROCESSING_FEE,
    ),
  };
};
